public async Task<bool> PurchaseTicketsAsync(int eventId, int purchaseQuantity)
{
    using (var context = new EventBookingContext())
    {
        using (var transaction = await context.Database.BeginTransactionAsync())
        {
            try
            {
                var eventEntity = await context.Events
                    .Where(e => e.EventId == eventId)
                    .SingleOrDefaultAsync();

                if (eventEntity == null || eventEntity.AvailableSeats < purchaseQuantity)
                {
                    return false; // Not enough seats available or event not found
                }

                eventEntity.AvailableSeats -= purchaseQuantity;
                context.Events.Update(eventEntity);

                await context.SaveChangesAsync();
                await transaction.CommitAsync();

                return true;
            }
            catch (Exception)
            {
                await transaction.RollbackAsync();
                return false;
            }
        }
    }
